#include <bits/stdc++.h>
using namespace std;

const int N=1010;

int n,m,a[N][N],h[N],l[N],r[N],stk[N],top,ans;

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            char s[2];
            scanf("%s",s);
            a[i][j]=(s[0]=='F');
        }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            if(a[i][j]) h[j]=h[j]+1;
            else h[j]=0;
        }
        for(int j=1;j<=m;j++){
            while(h[stk[top]]>h[j])
                r[stk[top]]=j,top--;
            stk[++top]=j;
        }
        while(top)
            r[stk[top]]=m+1,top--;
        for(int j=m;j;j--){
            while(h[stk[top]]>h[j])
                l[stk[top]]=j,top--;
            stk[++top]=j;
        }
        while(top)
            l[stk[top]]=0,top--;
        for(int j=1;j<=m;j++)
            ans=max(ans,(r[j]-l[j]-1)*h[j]);
    }
    printf("%d",ans*3);
    return 0;
}
